function durationNaturalLanguage(duration){const days=Math.floor(duration/(1000*60*60*24));const hours=Math.floor((duration%(1000*60*60*24))/(1000*60*60));const minutes=Math.floor((duration%(1000*60*60))/(1000*60));let durationNL='';if(days>0){durationNL+=`${days} day${days > 1 ? 's' : ''} `}
if(hours>0){if(durationNL.length>0){durationNL+=', '}
durationNL+=`${hours} h `}
if(minutes>0){if(hours>0){unit=''}else{unit='minute '}
if(durationNL.length>0){durationNL+=', '}
durationNL+=`${minutes} ${unit}${minutes > 1 ? 's' : ''}`}
return durationNL.trim()}
var timeZone='America/Los_Angeles';const selectElement=document.querySelector('#select-timezone');selectElement.innerHTML='';const select=document.createElement('select');let option=document.createElement('option');option.value=timeZone;option.text='OpenSim/SL Time';select.appendChild(option);const userTimeZone=Intl.DateTimeFormat().resolvedOptions().timeZone;if(userTimeZone!==timeZone){option=document.createElement('option');option.value=userTimeZone;option.text=userTimeZone;select.appendChild(option)}
const timeZones=moment.tz.names();for(const tz of timeZones){if(tz!==timeZone&&tz!==userTimeZone){option=document.createElement('option');option.value=tz;option.text=tz;select.appendChild(option)}}
select.addEventListener('change',function(){timeZone=this.value;refreshCalendar(timeZone)});selectElement.appendChild(select);$(select).select2();$(select).select2().on('change',function(){timeZone=this.value;refreshCalendar(timeZone)});function updateClock(){const slTimeElement=document.querySelector('#sltime');setInterval(()=>{const time=moment().tz('America/Los_Angeles').format('MMM D, YYYY hh:mm:ss A');slTimeElement.innerHTML=time},1000)}
updateClock();function toSlug(text){return window.slugify(text,{lower:!0,strict:!0})}
function updateStatus(message){const statusElement=document.querySelector('#notices');statusElement.innerHTML=message}
function getUniqueWeekNumber(d){const referenceDate=moment.tz('1970-01-05',timeZone);const days=d.diff(referenceDate,'days');return Math.floor(days/7)}
function refreshCalendar(timeZone){const eventsContainer=document.getElementById('events-container');eventsContainer.innerHTML='';updateStatus('Warming up the time machine... <i class="fas fa-spinner fa-spin"></i>');fetch('events.json').then(response=>response.json()).then(events=>{const nowUser=new Date();const todayUser=nowUser.toISOString().split('T')[0];if(!Array.isArray(events)){throw new Error('Unable to read data source.')}
updateStatus('Reading calendars... <i class="fas fa-spinner fa-spin"></i>');const eventsByWeek={};events.forEach(event=>{if(!event.hasOwnProperty('start')){throw new Error('Un événement n\'a pas de propriété \'start\'')}
const startDate=moment(event.start).tz(timeZone).toDate();const endDate=moment(event.end).tz(timeZone).toDate();const weekNumber=getUniqueWeekNumber(moment(startDate));if(!eventsByWeek[weekNumber]){eventsByWeek[weekNumber]={}}
const day=moment(startDate).tz(timeZone).format('YYYY-MM-DD');if(!eventsByWeek[weekNumber][day]){eventsByWeek[weekNumber][day]=[]}
eventsByWeek[weekNumber][day].push(event)});updateStatus('Tidying up... <i class="fas fa-spinner fa-spin"></i>');Object.keys(eventsByWeek).forEach(weekNumber=>{const weekElement=document.createElement('div');weekElement.id=`week-${weekNumber}`;weekElement.classList.add('week');Object.keys(eventsByWeek[weekNumber]).forEach(day=>{const dayElement=document.createElement('div');const dateObject=new Date(`${day}T00:00`);dayElement.id=`day-${day}`;const options={weekday:'long',year:'numeric',month:'long',day:'numeric'};const formattedDate=dateObject.toLocaleDateString(undefined,options);dayElement.classList.add('day',`day-${toSlug(formattedDate)}`);const now=new Date();if(now.toISOString().split('T')[0]===day){dayElement.classList.add('today')}
const factor=4;const maxPercentage=40;const maxEvents=Math.ceil(maxPercentage/factor);const eventCount=Math.min(eventsByWeek[weekNumber][day].length,maxEvents);const stretch=factor*eventCount;const flexBasis=`calc(8% + ${stretch}%)`;dayElement.style.flexBasis=flexBasis;dayElement.innerHTML=`<h3>${formattedDate}</h3>`;eventsByWeek[weekNumber][day].forEach(event=>{const eventElement=document.createElement('div');eventElement.id=`event-${event.hash}`;eventElement.classList.add('event',...event.tags.map(tag=>`tag-${toSlug(tag)}`));const now=new Date();if(now>=new Date(event.start)&&now<=new Date(event.end)){eventElement.classList.add('ongoing')}
const eventDayUser=new Date(event.start).toISOString().split('T')[0];if(eventDayUser===todayUser){eventElement.classList.add('today-user')}
const options={hour:'numeric',minute:'numeric'};const startLA=new Date(event.start).toLocaleString(undefined,{timeZone,hour:'numeric',minute:'numeric'});const endLA=new Date(event.end).toLocaleString(undefined,{timeZone,hour:'numeric',minute:'numeric'});const teleportLinks=Object.entries(event.teleport).map(([key,value])=>`<a class="tplink" href="${value}" target="_blank">${key}</a>`).join(' ');eventElement.innerHTML=`
                    <h4 class=title>${event.title}</h4>
                    <p class=time><span class=start>${startLA}</span> <span class=end>${endLA}</span></p>
                    <p class=description>${event.description}</p>
                    <p class=teleport>${event.hgurl} <span class=tplinks>${teleportLinks}</span></p>
                    <p class=tags>${event.tags}</p>
                    `;dayElement.appendChild(eventElement)});weekElement.appendChild(dayElement)});eventsContainer.appendChild(weekElement)});updateStatus('')}).catch(error=>{console.error('Erreur:',error)})}
refreshCalendar(timeZone);const header=document.querySelector('header');const sticky=header.offsetTop;window.addEventListener('scroll',function(){if(window.pageYOffset>sticky){header.classList.add('sticky')}else{header.classList.remove('sticky')}});document.querySelectorAll('nav li.section').forEach(function(menuItem){menuItem.addEventListener('click',function(){document.querySelectorAll('section').forEach(function(section){section.style.display='none'});var target=this.getAttribute('data-target');document.getElementById(target).style.display='block'})})